package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.util.Arrays;
import java.util.List;

class CartTest {

  // Since LineItem class is not found, we create a minimal stub class here for testing
  static class LineItem {}

  @Test
  void testGetLineItems() throws Exception {
    LineItem item1 = new LineItem();
    LineItem item2 = new LineItem();
    List<LineItem> items = Arrays.asList(item1, item2);

    // Instead of using Class.forName, directly use Cart.class since Cart is in the same package
    Class<?> cartClass = Cart.class;
    Object cart = cartClass.getConstructor(List.class, String.class, String.class)
                          .newInstance(items, "buyerName", "1234-5678-9876-5432");

    @SuppressWarnings("unchecked")
    List<LineItem> result = (List<LineItem>) cartClass.getMethod("getLineItems").invoke(cart);

    assertNotNull(result);
    assertEquals(2, result.size());
    assertSame(item1, result.get(0));
    assertSame(item2, result.get(1));
  }
}
